INSERT INTO public.kb_articles (title, content, category, language, tags, is_published, is_internal) VALUES

-- ================== MANAGEMENT ARTICLES ==================

('ลบ eSIM ได้ไหม?', 
E'## สามารถลบ eSIM ได้ไหม?\n\nได้ครับ/ค่ะ คุณสามารถลบ eSIM จากอุปกรณ์ได้ตลอดเวลา\n\n### ข้อควรระวัง\n\n**สำคัญ:** เมื่อลบ eSIM แล้ว จะไม่สามารถกู้คืนหรือติดตั้งใหม่ได้ ข้อมูลที่เหลือและวันที่เหลือจะหายไปถาวร\n\n### วิธีลบ eSIM\n\n**iPhone:**\n1. ไปที่ Settings > Cellular\n2. เลือก eSIM ที่ต้องการลบ\n3. แตะ "Delete eSIM"\n4. ยืนยันการลบ\n\n**Android:**\n1. ไปที่ Settings > Network & Internet > SIMs\n2. เลือก eSIM ที่ต้องการลบ\n3. แตะ "Delete" หรือ "Remove"\n4. ยืนยันการลบ\n\n### คำแนะนำ\n\n- ลบ eSIM เฉพาะเมื่อใช้งานเสร็จแล้วหรือหมดอายุแล้ว\n- หากยังมีข้อมูลเหลือ แนะนำให้ใช้ให้หมดก่อนลบ\n- ติดต่อฝ่ายบริการหากต้องการความช่วยเหลือ',
'management', 'th', ARRAY['ลบ', 'esim', 'remove', 'delete'], true, false),

('ติดตั้ง/ใช้ซ้ำ eSIM ได้ไหม?',
E'## ติดตั้งหรือใช้ซ้ำ eSIM ได้ไหม?\n\n**ไม่ได้ครับ/ค่ะ** eSIM ส่วนใหญ่สามารถติดตั้งได้ครั้งเดียวเท่านั้น\n\n### ทำไมถึงติดตั้งซ้ำไม่ได้?\n\neSIM มีการผูกกับอุปกรณ์เครื่องแรกที่ติดตั้ง เพื่อความปลอดภัย:\n- QR Code ใช้ได้ครั้งเดียว\n- รหัสเปิดใช้งานใช้ได้ครั้งเดียว\n- ไม่สามารถย้ายไปอุปกรณ์อื่นได้\n\n### ข้อยกเว้น\n\nบาง eSIM รองรับการติดตั้งซ้ำ โปรดตรวจสอบรายละเอียดแพ็คเกจก่อนซื้อ\n\n### คำแนะนำ\n\n- **อย่าลบ eSIM** หากยังต้องการใช้งาน\n- ติดตั้งบนอุปกรณ์ที่จะใช้งานจริง\n- หากติดตั้งผิดเครื่อง ติดต่อฝ่ายบริการ',
'management', 'th', ARRAY['ติดตั้ง', 'ใช้ซ้ำ', 'reinstall', 'reuse'], true, false),

('ใช้ eSIM หลายเครื่องได้ไหม?',
E'## ใช้ eSIM บนหลายอุปกรณ์ได้ไหม?\n\n**ไม่ได้ครับ/ค่ะ** eSIM หนึ่งตัวใช้ได้กับอุปกรณ์เครื่องเดียวเท่านั้น\n\n### ข้อจำกัด\n\n- eSIM ผูกกับอุปกรณ์ที่ติดตั้งครั้งแรก\n- ไม่สามารถย้ายไปเครื่องอื่นได้\n- ไม่สามารถใช้พร้อมกันหลายเครื่อง\n\n### ทางเลือก\n\nหากต้องการใช้เน็ตหลายเครื่อง:\n- **ซื้อ eSIM หลายตัว** - แต่ละเครื่องใช้ eSIM ของตัวเอง\n- **ใช้ Hotspot** - แชร์เน็ตจากเครื่องหลักไปยังเครื่องอื่น (ถ้าแพ็คเกจรองรับ)\n\n### ตรวจสอบก่อนซื้อ\n\nหากต้องการใช้ Hotspot ให้ตรวจสอบว่าแพ็คเกจรองรับก่อนซื้อ',
'management', 'th', ARRAY['หลายเครื่อง', 'multiple devices', 'transfer'], true, false),

('eSIM หมดอายุแล้วจะเป็นอย่างไร?',
E'## eSIM หมดอายุแล้วจะเป็นอย่างไร?\n\nเมื่อ eSIM หมดอายุ คุณจะไม่สามารถใช้เน็ตได้อีกต่อไป\n\n### สิ่งที่เกิดขึ้นเมื่อหมดอายุ\n\n1. **เน็ตหยุดทำงาน** - ไม่สามารถใช้ข้อมูลได้\n2. **ข้อมูลที่เหลือหายไป** - ไม่สามารถใช้หรือโอนได้\n3. **eSIM ยังอยู่ในเครื่อง** - แต่ใช้งานไม่ได้\n\n### ต้องทำอย่างไร?\n\n**ก่อนหมดอายุ:**\n- ตรวจสอบวันหมดอายุในแอปหรือเว็บไซต์\n- ใช้ข้อมูลให้หมดก่อนหมดอายุ\n- ซื้อแพ็คเกจใหม่ล่วงหน้าหากยังต้องการใช้\n\n**หลังหมดอายุ:**\n- ลบ eSIM ที่หมดอายุออกจากเครื่อง\n- ซื้อ eSIM ใหม่และติดตั้งใหม่\n\n### หมายเหตุ\n\nอายุการใช้งานเริ่มนับตั้งแต่วันที่เปิดใช้งาน eSIM ไม่ใช่วันที่ซื้อ',
'management', 'th', ARRAY['หมดอายุ', 'expire', 'validity'], true, false),

-- ================== TROUBLESHOOT ARTICLES ==================

('ข้อผิดพลาด "ไม่สามารถเพิ่มแผนมือถือได้"',
E'## แก้ไขข้อผิดพลาด "Cellular Plans Cannot Be Added"\n\nหากเห็นข้อความนี้ ลองทำตามขั้นตอนด้านล่าง\n\n### สาเหตุที่เป็นไปได้\n\n1. **อุปกรณ์ไม่รองรับ eSIM**\n2. **อุปกรณ์ล็อคเครือข่าย**\n3. **เชื่อมต่ออินเทอร์เน็ตไม่ได้**\n4. **QR Code ถูกใช้แล้ว**\n\n### วิธีแก้ไข\n\n**ขั้นตอนที่ 1:** ตรวจสอบการเชื่อมต่อ\n- เชื่อมต่อ WiFi ที่เสถียร\n- ปิด VPN ถ้ามี\n\n**ขั้นตอนที่ 2:** รีสตาร์ทเครื่อง\n- ปิดเครื่องแล้วเปิดใหม่\n- ลองสแกน QR Code อีกครั้ง\n\n**ขั้นตอนที่ 3:** ตรวจสอบอุปกรณ์\n- ไปที่ Settings > General > About\n- ตรวจสอบว่ามี "Digital SIM" หรือ "eSIM"\n\n**ขั้นตอนที่ 4:** ตรวจสอบสถานะล็อค\n- ติดต่อผู้ให้บริการเดิมเพื่อปลดล็อค\n\n### ยังไม่ได้ผล?\n\nติดต่อฝ่ายบริการพร้อมภาพหน้าจอ error',
'troubleshoot', 'th', ARRAY['cellular plans', 'error', 'ไม่สามารถเพิ่ม', 'ติดตั้งไม่ได้'], true, false),

('เน็ตไม่ทำงานหลังลงจอด',
E'## เน็ตไม่ทำงานหลังถึงที่หมาย\n\nลงเครื่องแล้วแต่เน็ตยังไม่ทำงาน? ลองทำตามขั้นตอนนี้\n\n### ขั้นตอนที่ 1: เปิด Data Roaming\n\n**iPhone:**\n1. Settings > Cellular > Cellular Data Options\n2. เปิด Data Roaming\n3. เลือก eSIM เป็น Cellular Data\n\n**Android:**\n1. Settings > Network & Internet > SIMs\n2. เลือก eSIM\n3. เปิด Roaming\n\n### ขั้นตอนที่ 2: เปิด/ปิด Airplane Mode\n\n1. เปิด Airplane Mode\n2. รอ 30 วินาที\n3. ปิด Airplane Mode\n4. รอให้เชื่อมต่อเครือข่าย\n\n### ขั้นตอนที่ 3: เลือกเครือข่ายด้วยตนเอง\n\n1. ไปที่ Settings > Cellular > Network Selection\n2. ปิด Automatic\n3. เลือกเครือข่ายที่รองรับ\n\n### ขั้นตอนที่ 4: รีสตาร์ทเครื่อง\n\nปิดเครื่องแล้วเปิดใหม่\n\n### ยังไม่ได้ผล?\n\nติดต่อฝ่ายบริการพร้อมข้อมูล:\n- รุ่นอุปกรณ์\n- ประเทศที่ใช้งาน\n- ภาพหน้าจอการตั้งค่า',
'troubleshoot', 'th', ARRAY['เน็ตไม่ทำงาน', 'ลงจอด', 'data not working', 'landing'], true, false),

('ความเร็วเน็ตช้า',
E'## แก้ไขปัญหาความเร็วเน็ตช้า\n\nเน็ตช้ากว่าที่คาดหวัง? ลองทำตามขั้นตอนเหล่านี้\n\n### สาเหตุที่เป็นไปได้\n\n1. **สัญญาณอ่อน** - อยู่ในพื้นที่ที่สัญญาณไม่ดี\n2. **เครือข่ายหนาแน่น** - มีผู้ใช้งานมากในช่วงเวลานั้น\n3. **ใช้ข้อมูลเกินโควต้า** - ความเร็วถูกจำกัดหลังใช้ครบ\n4. **การตั้งค่าไม่ถูกต้อง** - APN หรือเครือข่ายไม่ถูกต้อง\n\n### วิธีแก้ไข\n\n**ขั้นตอนที่ 1:** ตรวจสอบสัญญาณ\n- ย้ายไปพื้นที่โล่ง\n- หลีกเลี่ยงอาคารหนา\n\n**ขั้นตอนที่ 2:** สลับเครือข่าย\n- ไปที่ Network Selection\n- เลือกเครือข่ายอื่นที่มีสัญญาณดีกว่า\n\n**ขั้นตอนที่ 3:** เปิด/ปิด Airplane Mode\n- ช่วยให้เครื่องเชื่อมต่อเครือข่ายใหม่\n\n**ขั้นตอนที่ 4:** ตรวจสอบการใช้งาน\n- เช็คว่าใช้ข้อมูลเกินโควต้าหรือยัง\n- แพ็คเกจบางแบบลดความเร็วหลังใช้ครบ\n\n### หมายเหตุ\n\nความเร็วขึ้นอยู่กับเครือข่ายท้องถิ่นและพื้นที่ใช้งาน',
'troubleshoot', 'th', ARRAY['ช้า', 'slow', 'speed', 'ความเร็ว'], true, false),

('ข้อผิดพลาด "รหัสนี้ไม่สามารถใช้ได้อีกแล้ว"',
E'## แก้ไขข้อผิดพลาด "This Code Is No Longer Valid"\n\nหากเห็นข้อความนี้ หมายความว่า QR Code หรือรหัสเปิดใช้งานถูกใช้ไปแล้ว\n\n### สาเหตุที่เป็นไปได้\n\n1. **eSIM ถูกติดตั้งแล้ว** - บนอุปกรณ์เครื่องนี้หรือเครื่องอื่น\n2. **สแกนซ้ำ** - QR Code ถูกสแกนไปแล้วก่อนหน้านี้\n3. **eSIM หมดอายุ** - รหัสเปิดใช้งานหมดอายุ\n\n### ตรวจสอบก่อน\n\n**เช็คว่า eSIM ติดตั้งแล้วหรือยัง:**\n- iPhone: Settings > Cellular > ดูรายการ SIM\n- Android: Settings > Network & Internet > SIMs\n\nหาก eSIM อยู่ในรายการแล้ว แสดงว่าติดตั้งสำเร็จแล้ว\n\n### วิธีแก้ไข\n\nหาก eSIM ไม่อยู่ในรายการ:\n1. ติดต่อฝ่ายบริการ\n2. แจ้งหมายเลขออเดอร์\n3. เราจะตรวจสอบและช่วยเหลือ\n\n### คำแนะนำ\n\n- สแกน QR Code ครั้งเดียว\n- รอจนกระบวนการเสร็จสมบูรณ์\n- อย่าปิดหน้าจอระหว่างติดตั้ง',
'troubleshoot', 'th', ARRAY['code invalid', 'รหัสไม่ถูกต้อง', 'ใช้แล้ว'], true, false),

('ไม่สามารถสแกน QR Code ได้',
E'## แก้ไขปัญหาสแกน QR Code ไม่ได้\n\nหากไม่สามารถสแกน QR Code ได้ ลองทำตามขั้นตอนนี้\n\n### วิธีที่ 1: ป้อนรหัสด้วยตนเอง\n\nแทนที่จะสแกน คุณสามารถป้อนรหัสได้:\n\n**iPhone:**\n1. Settings > Cellular > Add eSIM\n2. เลือก "Enter Details Manually"\n3. ป้อน SM-DP+ Address และ Activation Code\n\n**Android:**\n1. Settings > Network & Internet > SIMs\n2. เลือก "Add eSIM"\n3. เลือก "Enter code instead"\n4. ป้อนรหัส\n\n### วิธีที่ 2: ตรวจสอบ QR Code\n\n- ซูมเข้าที่ QR Code\n- ให้แสงสว่างเพียงพอ\n- ถือเครื่องให้นิ่ง\n- ลดแสงสะท้อนบนหน้าจอ\n\n### วิธีที่ 3: ใช้อุปกรณ์อื่นแสดง QR Code\n\n- เปิด QR Code บนคอมพิวเตอร์หรือแท็บเล็ต\n- ใช้โทรศัพท์สแกนจากหน้าจออุปกรณ์อื่น\n\n### ยังไม่ได้ผล?\n\nติดต่อฝ่ายบริการเพื่อขอรหัสเปิดใช้งานแบบข้อความ',
'troubleshoot', 'th', ARRAY['สแกนไม่ได้', 'qr code', 'scan'], true, false),

('eSIM ไม่แสดงในการตั้งค่า',
E'## eSIM ไม่แสดงในการตั้งค่า\n\nติดตั้ง eSIM แล้วแต่ไม่เห็นในรายการ? ลองทำตามนี้\n\n### ขั้นตอนที่ 1: ตรวจสอบตำแหน่งที่ถูกต้อง\n\n**iPhone:**\n- Settings > Cellular\n- ดูที่ "SIMs" หรือ "Cellular Plans"\n\n**Android:**\n- Settings > Network & Internet > SIMs\n- หรือ Settings > Connections > SIM Manager\n\n### ขั้นตอนที่ 2: รีสตาร์ทเครื่อง\n\nปิดเครื่องแล้วเปิดใหม่\n\n### ขั้นตอนที่ 3: อัพเดทซอฟต์แวร์\n\n- iPhone: Settings > General > Software Update\n- Android: Settings > System > Software Update\n\n### ขั้นตอนที่ 4: รีเซ็ตการตั้งค่าเครือข่าย\n\n**iPhone:**\n1. Settings > General > Transfer or Reset iPhone\n2. Reset > Reset Network Settings\n\n**Android:**\n1. Settings > System > Reset options\n2. Reset Wi-Fi, mobile & Bluetooth\n\n### ยังไม่เห็น?\n\neSIM อาจยังไม่ได้ติดตั้งสำเร็จ ลองติดตั้งใหม่อีกครั้ง หากยังไม่ได้ผล ติดต่อฝ่ายบริการ',
'troubleshoot', 'th', ARRAY['ไม่แสดง', 'not showing', 'settings'], true, false),

('เครื่องค้างระหว่างติดตั้ง eSIM',
E'## แก้ไขปัญหาเครื่องค้างระหว่างติดตั้ง\n\nหากเครื่องค้างขณะติดตั้ง eSIM อย่าตกใจ ทำตามขั้นตอนนี้\n\n### ขั้นตอนที่ 1: รอสักครู่\n\nการติดตั้งอาจใช้เวลา 2-5 นาที อย่าปิดเครื่องหรือปิดแอป\n\n### ขั้นตอนที่ 2: ตรวจสอบการเชื่อมต่อ\n\n- ตรวจสอบว่า WiFi ยังเชื่อมต่ออยู่\n- หลีกเลี่ยงการใช้ VPN\n\n### ขั้นตอนที่ 3: รีสตาร์ทเครื่อง\n\nหากค้างนานกว่า 5 นาที:\n1. กดปุ่มเปิด/ปิดค้างไว้\n2. เลือก Restart หรือ Force Restart\n3. ตรวจสอบว่า eSIM ติดตั้งแล้วหรือยัง\n\n### ขั้นตอนที่ 4: ตรวจสอบสถานะ\n\nไปที่ Settings > Cellular ดูว่า eSIM แสดงในรายการหรือไม่\n\n### กรณี eSIM ไม่แสดง\n\nหาก eSIM ไม่แสดงหลังรีสตาร์ท:\n- ลองติดตั้งใหม่ด้วย QR Code หรือรหัส\n- หากไม่ได้ผล ติดต่อฝ่ายบริการ',
'troubleshoot', 'th', ARRAY['ค้าง', 'freeze', 'stuck', 'installing'], true, false),

('APN คืออะไรและตั้งค่าอย่างไร',
E'## APN คืออะไร?\n\nAPN (Access Point Name) คือการตั้งค่าที่บอกเครื่องว่าจะเชื่อมต่ออินเทอร์เน็ตอย่างไร\n\n### ต้องตั้งค่า APN ไหม?\n\n**ส่วนใหญ่ไม่ต้อง!** eSIM ของ Mobile11 ตั้งค่า APN อัตโนมัติ\n\n### เมื่อไหร่ต้องตั้งค่าเอง?\n\nบางกรณีอาจต้องตั้งค่าด้วยตนเอง:\n- เน็ตไม่ทำงานหลังติดตั้ง\n- ได้รับคำแนะนำจากฝ่ายบริการ\n\n### วิธีตั้งค่า APN\n\n**iPhone:**\n1. Settings > Cellular > Cellular Data Options\n2. Cellular Network > APN Settings\n3. ป้อนค่า APN ตามที่ได้รับแจ้ง\n\n**Android:**\n1. Settings > Network & Internet > SIMs\n2. เลือก eSIM > Access Point Names\n3. แตะ + เพื่อเพิ่ม APN ใหม่\n4. ป้อนค่าและบันทึก\n\n### ค่า APN ทั่วไป\n\nโดยปกติ APN สำหรับ Mobile11 คือ:\n- **APN:** mobile11 หรือ internet\n- ปล่อยช่องอื่นว่างไว้\n\nหากไม่แน่ใจ ติดต่อฝ่ายบริการเพื่อขอค่า APN ที่ถูกต้อง',
'troubleshoot', 'th', ARRAY['apn', 'access point', 'ตั้งค่า'], true, false),

-- ================== BILLING ARTICLES ==================

('ติดต่อฝ่ายบริการลูกค้าได้อย่างไร?',
E'## ติดต่อฝ่ายบริการลูกค้า\n\nเราพร้อมช่วยเหลือคุณตลอด 24 ชั่วโมง!\n\n### ช่องทางติดต่อ\n\n**1. แชทสด (เร็วที่สุด)**\n- คลิกไอคอนแชทที่มุมขวาล่าง\n- ตอบกลับภายใน 5 นาที\n- รองรับภาษาไทยและอังกฤษ\n\n**2. อีเมล**\n- support@mobile11.com\n- ตอบกลับภายใน 24 ชั่วโมง\n\n**3. Help Center**\n- เข้าไปที่ mobile11.com/support\n- มีบทความช่วยเหลือมากกว่า 50 หัวข้อ\n\n### ข้อมูลที่ควรเตรียม\n\nเพื่อให้เราช่วยเหลือได้เร็วขึ้น กรุณาเตรียม:\n- หมายเลขออเดอร์ หรือ ICCID\n- รุ่นอุปกรณ์ (เช่น iPhone 15)\n- ประเทศที่ใช้งาน\n- ภาพหน้าจอ (ถ้ามี error)\n\n### เวลาทำการ\n\n- **แชทสด:** 24/7\n- **อีเมล:** ตอบกลับทุกวัน\n\nเราตั้งใจให้บริการที่ดีที่สุด! 💚',
'billing', 'th', ARRAY['ติดต่อ', 'contact', 'support', 'ช่วยเหลือ'], true, false),

('นโยบายการคืนเงินคืออะไร?',
E'## นโยบายการคืนเงิน\n\nเราต้องการให้คุณพอใจกับบริการของเรา\n\n### เงื่อนไขการคืนเงิน\n\n**สามารถขอคืนเงินได้เมื่อ:**\n- eSIM ยังไม่ได้ติดตั้ง\n- มีปัญหาทางเทคนิคที่เราแก้ไขไม่ได้\n- ซื้อซ้ำโดยไม่ตั้งใจ\n\n**ไม่สามารถคืนเงินได้เมื่อ:**\n- eSIM ถูกเปิดใช้งานแล้ว\n- ใช้ข้อมูลไปแล้วบางส่วน\n- หมดอายุแล้ว\n- ผู้ใช้เปลี่ยนใจหลังเปิดใช้งาน\n\n### วิธีขอคืนเงิน\n\n1. ติดต่อฝ่ายบริการผ่านแชท\n2. แจ้งหมายเลขออเดอร์\n3. อธิบายเหตุผล\n4. รอการตรวจสอบ (1-2 วันทำการ)\n\n### ระยะเวลาคืนเงิน\n\n- **บัตรเครดิต/เดบิต:** 5-10 วันทำการ\n- **พร้อมเพย์:** 1-3 วันทำการ\n\n### หมายเหตุ\n\nการคืนเงินจะโอนกลับไปยังช่องทางเดิมที่ชำระเงิน',
'billing', 'th', ARRAY['คืนเงิน', 'refund', 'นโยบาย', 'policy'], true, false),

('จะได้รับ eSIM เมื่อไหร่?',
E'## จะได้รับ eSIM เมื่อไหร่?\n\n**ทันทีหลังชำระเงินสำเร็จ!** ⚡\n\n### การส่งมอบ\n\nเมื่อชำระเงินเสร็จ คุณจะได้รับ:\n\n1. **หน้าเว็บแสดง QR Code** - ทันที\n2. **อีเมลยืนยัน** - ภายใน 1-2 นาที\n3. **เข้าถึงใน "My eSIMs"** - ทันที\n\n### วิธีเข้าถึง eSIM\n\n**ตัวเลือกที่ 1:** หน้ายืนยันการสั่งซื้อ\n- หลังชำระเงิน จะแสดง QR Code ทันที\n- สแกนเพื่อติดตั้ง\n\n**ตัวเลือกที่ 2:** อีเมล\n- เช็คอีเมลที่ใช้สั่งซื้อ\n- มี QR Code และรหัสเปิดใช้งาน\n\n**ตัวเลือกที่ 3:** บัญชีผู้ใช้\n- เข้าสู่ระบบที่ mobile11.com\n- ไปที่ "My eSIMs"\n- ดู QR Code และรายละเอียด\n\n### ไม่ได้รับอีเมล?\n\n- ตรวจสอบโฟลเดอร์ Spam/Junk\n- ตรวจสอบว่าพิมพ์อีเมลถูกต้อง\n- ติดต่อฝ่ายบริการพร้อมหมายเลขออเดอร์',
'billing', 'th', ARRAY['ได้รับ', 'delivery', 'เมื่อไหร่', 'when'], true, false),

-- ================== PLANS ARTICLES ==================

('แพ็คเกจ Day Pass คืออะไร?',
E'## แพ็คเกจ Day Pass\n\nDay Pass เหมาะสำหรับผู้ที่ต้องการเน็ตแบบรายวัน\n\n### หลักการทำงาน\n\n- ได้รับข้อมูลจำนวนหนึ่ง**ต่อวัน**\n- รีเซ็ตทุกวันตามเวลาท้องถิ่น\n- ใช้ได้ตามจำนวนวันที่ซื้อ\n\n### ตัวอย่าง\n\n**Day Pass 1GB/วัน 7 วัน:**\n- ได้ 1GB ต่อวัน\n- รีเซ็ตทุกเที่ยงคืน (เวลาท้องถิ่น)\n- ใช้ได้ 7 วัน\n- รวมทั้งหมด 7GB (ถ้าใช้เต็มทุกวัน)\n\n### ข้อดี\n\n✅ ไม่ต้องกังวลใช้หมดก่อนเวลา\n✅ มีข้อมูลใหม่ทุกวัน\n✅ เหมาะกับการใช้งานสม่ำเสมอ\n\n### ข้อควรรู้\n\n- ข้อมูลที่เหลือจากวันก่อนไม่สะสม\n- หากใช้ครบโควต้ารายวัน ต้องรอวันใหม่\n- บางแพ็คเกจอาจลดความเร็วหลังใช้ครบแทนที่จะหยุด\n\n### เหมาะกับใคร?\n\n- นักท่องเที่ยวที่ต้องการความแน่นอน\n- ผู้ที่ใช้เน็ตสม่ำเสมอทุกวัน\n- ผู้ที่ไม่ต้องการประหยัดข้อมูล',
'plans', 'th', ARRAY['day pass', 'รายวัน', 'daily', 'แพ็คเกจ'], true, false),

('แพ็คเกจ Limitless คืออะไร?',
E'## แพ็คเกจ Limitless (เน็ตไม่อั้น)\n\nLimitless คือแพ็คเกจเน็ตไม่จำกัดสำหรับผู้ใช้งานหนัก\n\n### หลักการทำงาน\n\n- **ไม่จำกัดข้อมูล** ใช้ได้เท่าที่ต้องการ\n- ความเร็วตามที่ระบุ (เช่น 4G/5G)\n- ใช้ได้ตลอดระยะเวลาแพ็คเกจ\n\n### ข้อดี\n\n✅ ไม่ต้องกังวลเรื่องข้อมูล\n✅ ใช้ได้ไม่อั้น\n✅ ดู streaming, video call สบายใจ\n✅ ไม่มีค่าใช้จ่ายเพิ่มเติม\n\n### Fair Usage Policy (FUP)\n\nแพ็คเกจ Limitless อาจมี FUP:\n- หลังใช้ถึงขีดจำกัด (เช่น 50GB) ความเร็วอาจลดลง\n- ยังใช้ได้ต่อแต่ช้าลง\n- ตรวจสอบรายละเอียดก่อนซื้อ\n\n### เหมาะกับใคร?\n\n- ผู้ใช้งานหนัก\n- ผู้ที่ทำงาน remote\n- ผู้ที่ดู video/streaming บ่อย\n- ผู้ที่ไม่อยากนับ data usage\n\n### เปรียบเทียบ\n\n| | Limitless | Max Speed |\n|---|---|---|\n| ข้อมูล | ไม่จำกัด | จำกัดตามแพ็คเกจ |\n| ความเร็ว | อาจลดหลัง FUP | เต็มที่จนหมด |\n| ราคา | สูงกว่า | ต่ำกว่า |',
'plans', 'th', ARRAY['limitless', 'unlimited', 'ไม่อั้น', 'ไม่จำกัด'], true, false),

('แพ็คเกจ Max Speed คืออะไร?',
E'## แพ็คเกจ Max Speed\n\nMax Speed เป็นแพ็คเกจที่เน้นความเร็วสูงสุดจนกว่าจะใช้ข้อมูลหมด\n\n### หลักการทำงาน\n\n- ได้รับข้อมูลตามที่ซื้อ (เช่น 5GB, 10GB)\n- ความเร็วเต็มที่ตลอดการใช้งาน\n- ใช้ได้จนกว่าข้อมูลจะหมดหรือหมดอายุ\n\n### ข้อดี\n\n✅ ความเร็วสูงสุดตลอด\n✅ ราคาประหยัดกว่า Limitless\n✅ เหมาะกับการใช้งานช่วงสั้น\n✅ ยืดหยุ่น - ใช้เมื่อต้องการ\n\n### ตัวอย่าง\n\n**Max Speed 5GB 7 วัน:**\n- ได้ 5GB ใช้ได้ 7 วัน\n- ความเร็ว 4G/5G ตลอด\n- ใช้วันละ 700MB หรือจะใช้ทีเดียว 5GB ก็ได้\n- หมดก่อน 7 วันถ้าใช้หมด\n\n### ข้อควรรู้\n\n- เมื่อข้อมูลหมด จะหยุดใช้งานได้\n- ต้องซื้อ top-up หรือแพ็คเกจใหม่\n- วางแผนการใช้ให้พอดี\n\n### เหมาะกับใคร?\n\n- ผู้ที่ใช้เน็ตปานกลาง\n- ผู้ที่อยากประหยัดงบ\n- ผู้ที่รู้ปริมาณการใช้งานตัวเอง\n- นักท่องเที่ยวทริปสั้น',
'plans', 'th', ARRAY['max speed', 'ความเร็วสูง', 'data cap', 'แพ็คเกจ'], true, false),

-- ================== USAGE ARTICLES ==================

('ตรวจสอบการใช้ข้อมูลได้ไหม?',
E'## ตรวจสอบการใช้ข้อมูล\n\nได้ครับ/ค่ะ! คุณสามารถตรวจสอบการใช้งานได้หลายวิธี\n\n### วิธีที่ 1: เว็บไซต์ Mobile11\n\n1. เข้าสู่ระบบที่ mobile11.com\n2. ไปที่ "My eSIMs"\n3. เลือก eSIM ที่ต้องการดู\n4. ดูข้อมูลการใช้งาน\n\n### วิธีที่ 2: การตั้งค่าในเครื่อง\n\n**iPhone:**\n1. Settings > Cellular\n2. ดูที่ "Cellular Data Usage"\n3. เลือก eSIM ที่ต้องการ\n\n**Android:**\n1. Settings > Network & Internet > SIMs\n2. เลือก eSIM\n3. ดู "Data usage"\n\n### ข้อควรรู้\n\n- ข้อมูลในเครื่องอาจไม่ตรงกับระบบ 100%\n- ใช้เว็บไซต์ Mobile11 เพื่อดูข้อมูลที่แม่นยำที่สุด\n- การอัพเดทอาจล่าช้า 15-30 นาที\n\n### แพ็คเกจ Day Pass\n\nสำหรับ Day Pass ระบบจะแสดง:\n- ข้อมูลที่ใช้วันนี้\n- ข้อมูลคงเหลือวันนี้\n- วันที่เหลือในแพ็คเกจ',
'usage', 'th', ARRAY['ตรวจสอบ', 'usage', 'data usage', 'เช็ค'], true, false),

('ใช้ Hotspot/แชร์เน็ตได้ไหม?',
E'## การใช้ Hotspot และแชร์เน็ต\n\n**ขึ้นอยู่กับแพ็คเกจที่ซื้อ** บางแพ็คเกจรองรับ บางแพ็คเกจไม่รองรับ\n\n### วิธีตรวจสอบ\n\nก่อนซื้อ ดูรายละเอียดแพ็คเกจ:\n- หากมีไอคอน Hotspot ✅ = รองรับ\n- หากไม่มี = ไม่รองรับ\n\n### วิธีเปิด Hotspot\n\n**iPhone:**\n1. Settings > Personal Hotspot\n2. เปิด "Allow Others to Join"\n3. ตั้งรหัส WiFi\n\n**Android:**\n1. Settings > Network & Internet\n2. Hotspot & Tethering\n3. เปิด Wi-Fi Hotspot\n\n### ข้อควรรู้\n\n- Hotspot ใช้ข้อมูลเร็วกว่าปกติ\n- อุปกรณ์ที่เชื่อมต่อจะใช้ข้อมูลของคุณ\n- แบตเตอรี่จะหมดเร็วขึ้น\n\n### ทำไมบางแพ็คเกจไม่รองรับ?\n\n- เป็นข้อกำหนดของผู้ให้บริการเครือข่าย\n- แพ็คเกจราคาถูกอาจจำกัดคุณสมบัตินี้\n- เลือกแพ็คเกจที่รองรับหากต้องการใช้',
'usage', 'th', ARRAY['hotspot', 'แชร์เน็ต', 'tethering', 'ปล่อย wifi'], true, false),

('เน็ตไม่อั้นทำงานอย่างไร?',
E'## เน็ตไม่อั้นทำงานอย่างไร?\n\nแพ็คเกจ Unlimited/Limitless ให้คุณใช้เน็ตได้ไม่จำกัด\n\n### หลักการทำงาน\n\n1. **ไม่มีโควต้าข้อมูล** - ใช้ได้เท่าที่ต้องการ\n2. **ความเร็วตามที่ระบุ** - 4G หรือ 5G\n3. **ใช้ได้ตลอดระยะเวลา** - จนกว่าจะหมดอายุ\n\n### Fair Usage Policy (FUP)\n\nแพ็คเกจส่วนใหญ่มี FUP:\n\n**ก่อนถึง FUP:**\n- ความเร็วเต็มที่ (4G/5G)\n- ใช้ได้ไม่จำกัด\n\n**หลังถึง FUP (เช่น 50GB):**\n- ความเร็วอาจลดลง (เช่น 1-3 Mbps)\n- ยังใช้ได้ต่อ ไม่หยุด\n- เพียงพอสำหรับ chat, email, browsing\n\n### ตรวจสอบ FUP ก่อนซื้อ\n\nดูรายละเอียดแพ็คเกจ:\n- FUP กี่ GB\n- ความเร็วหลัง FUP เท่าไหร่\n- บางแพ็คเกจไม่มี FUP เลย\n\n### เหมาะกับการใช้งานอะไร?\n\n✅ Social media\n✅ Video call\n✅ Streaming (ก่อน FUP)\n✅ Navigation\n✅ Email & browsing',
'usage', 'th', ARRAY['unlimited', 'ไม่อั้น', 'ไม่จำกัด', 'fup'], true, false),

('แพ็คเกจเริ่มต้นเมื่อไหร่?',
E'## แพ็คเกจเริ่มต้นเมื่อไหร่?\n\nขึ้นอยู่กับประเภทแพ็คเกจ:\n\n### แพ็คเกจแบบ "First Use"\n\n**เริ่มเมื่อ:** ใช้งานครั้งแรก\n\n- ติดตั้ง eSIM ได้ล่วงหน้า\n- อายุเริ่มนับเมื่อเชื่อมต่อเครือข่ายครั้งแรก\n- เหมาะสำหรับเตรียมก่อนเดินทาง\n\n### แพ็คเกจแบบ "On Install"\n\n**เริ่มเมื่อ:** ติดตั้ง eSIM สำเร็จ\n\n- อายุเริ่มนับทันทีที่ติดตั้ง\n- ควรติดตั้งเมื่อถึงที่หมาย\n- ตรวจสอบก่อนซื้อ\n\n### วิธีตรวจสอบ\n\nดูรายละเอียดแพ็คเกจ:\n- **"Validity starts on first use"** = First Use\n- **"Validity starts on installation"** = On Install\n\n### คำแนะนำ\n\n**First Use (แนะนำ):**\n- ติดตั้งก่อนเดินทาง 1-2 วัน\n- เปิดใช้งานเมื่อถึงที่หมาย\n- ไม่เสียเวลาติดตั้งที่สนามบิน\n\n**On Install:**\n- รอติดตั้งจนกว่าจะถึงที่หมาย\n- หรือติดตั้งวันที่ต้องการเริ่มใช้\n\n### หมายเหตุ\n\nแพ็คเกจส่วนใหญ่ของ Mobile11 เป็นแบบ First Use',
'usage', 'th', ARRAY['เริ่มต้น', 'validity', 'start', 'เมื่อไหร่'], true, false),

('เน็ตไม่อั้นรีเซ็ตเมื่อไหร่?',
E'## เน็ตไม่อั้นรีเซ็ตเมื่อไหร่?\n\nขึ้นอยู่กับประเภทแพ็คเกจ:\n\n### แพ็คเกจ Day Pass\n\n**รีเซ็ต:** ทุกวันเวลาเที่ยงคืน (ตามเวลาท้องถิ่น)\n\nตัวอย่าง Day Pass 1GB/วัน:\n- วันที่ 1: ใช้ 800MB → เหลือ 200MB → หมดวัน\n- วันที่ 2: รีเซ็ตเป็น 1GB ใหม่\n- ข้อมูลเหลือจากเมื่อวานไม่สะสม\n\n### แพ็คเกจ Limitless\n\n**ไม่มีการรีเซ็ต** - ใช้ได้ไม่จำกัดตลอดระยะเวลา\n\nแต่ถ้ามี FUP:\n- หลังใช้ถึง FUP ความเร็วจะลดลง\n- FUP อาจรีเซ็ตรายวันหรือไม่รีเซ็ต (ตรวจสอบรายละเอียด)\n\n### แพ็คเกจ Max Speed\n\n**ไม่มีการรีเซ็ต** - ใช้จนกว่าข้อมูลจะหมด\n\n### วิธีตรวจสอบ\n\n1. ดูรายละเอียดแพ็คเกจก่อนซื้อ\n2. Day Pass จะระบุข้อมูล "ต่อวัน"\n3. Max Speed จะระบุข้อมูลรวม\n4. Limitless จะระบุ "Unlimited"\n\n### เวลาท้องถิ่น\n\nการรีเซ็ตใช้เวลาของประเทศที่ใช้งาน ไม่ใช่เวลาประเทศไทย',
'usage', 'th', ARRAY['รีเซ็ต', 'reset', 'daily', 'เที่ยงคืน'], true, false),

